const scenario = $json;

return scenario.steps.map((step, index) => ({
  json: {
    run_id: scenario.run_id,
    scenario_id: scenario.id,
    scenario_name: scenario.name,
    phone: scenario.phone,
    step_index: index + 1,
    total_steps: scenario.steps.length,
    text: step.text,
    expect: step.expect || {},
    wait_ms: step.wait_ms || 3500
  }
}));

const now = new Date().toISOString();
const qaMessageId = `qa_${$json.scenario_id}_${$json.step_index}_${Date.now()}`;

const payload = {
  channel: "whatsapp",
  message_id: qaMessageId,
  timestamp: now,
  text: $json.text,
  message_type: "text",
  attachments: [],
  source_metadata: {
    test_mode: true,
    qa_run_id: $json.run_id,
    scenario_id: $json.scenario_id,
    step_index: $json.step_index
  },
  lead: {
    name: "Cliente QA",
    phone: $json.phone,
    external_id: $json.phone,
    channel: "whatsapp"
  }
};

return [
  {
    json: {
      ...$json,
      qa_message_id: qaMessageId,
      sent_at: now,
      inbound_payload: payload
    }
  }
];

const input = $("build_inbound_payload").item.json;

const lead = $("get_lead").item.json || {};
const previousState = $("get_state_before").item.json || {};
const currentState = $("get_state_after").item.json || {};
const lastMessage = $("get_last_outbound_message").item.json || {};
const lastAudit = $("get_last_audit").item.json || {};

const expect = input.expect || {};
const errors = [];

function normalize(value) {
  return String(value || "")
    .toLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .trim();
}

function includesAll(text, values = []) {
  const t = normalize(text);
  return values.every((v) => t.includes(normalize(v)));
}

function includesAny(text, values = []) {
  const t = normalize(text);
  return values.some((v) => t.includes(normalize(v)));
}

function notIncludesAny(text, values = []) {
  const t = normalize(text);
  return values.every((v) => !t.includes(normalize(v)));
}

const responseText = lastMessage.content || "";
const hasBotResponse = String(responseText || "").trim() !== "";

const lastBotAction = currentState.last_bot_action || null;
const stage = currentState.stage || null;
const nextGoal = currentState.next_goal || null;

const hasAction = lastBotAction !== null && String(lastBotAction).trim() !== "";

const stateChanged =
  String(previousState.stage || "") !== String(currentState.stage || "") ||
  String(previousState.next_goal || "") !== String(currentState.next_goal || "") ||
  String(previousState.service_interest || "") !== String(currentState.service_interest || "") ||
  String(previousState.vehicle_type || "") !== String(currentState.vehicle_type || "") ||
  String(previousState.district || "") !== String(currentState.district || "");

const hasAudit =
  !!lastAudit.flow_name ||
  !!lastAudit.decision ||
  !!lastAudit.idempotency_key;

// Reglas duras Prioridad 0
if (!hasBotResponse) {
  errors.push("bot es null o vacío");
}

if (!hasAudit) {
  errors.push("audit vacío: no hay flow_name, decision ni idempotency_key");
}

if (!hasBotResponse && !hasAction && !stateChanged) {
  errors.push("No hubo respuesta, acción ni cambio de estado");
}

// Validaciones esperadas del escenario
if (Array.isArray(expect.last_bot_action_any) && expect.last_bot_action_any.length > 0) {
  if (!expect.last_bot_action_any.includes(lastBotAction)) {
    errors.push(
      `last_bot_action esperado: ${expect.last_bot_action_any.join(", ")} | recibido: ${lastBotAction}`
    );
  }
}

if (Array.isArray(expect.stage_any) && expect.stage_any.length > 0) {
  if (!expect.stage_any.includes(stage)) {
    errors.push(
      `stage esperado: ${expect.stage_any.join(", ")} | recibido: ${stage}`
    );
  }
}

if (Array.isArray(expect.next_goal_any) && expect.next_goal_any.length > 0) {
  if (!expect.next_goal_any.includes(nextGoal)) {
    errors.push(
      `next_goal esperado: ${expect.next_goal_any.join(", ")} | recibido: ${nextGoal}`
    );
  }
}

if (Array.isArray(expect.response_includes) && expect.response_includes.length > 0) {
  if (!includesAll(responseText, expect.response_includes)) {
    errors.push(
      `respuesta no incluye todos: ${expect.response_includes.join(", ")}`
    );
  }
}

if (Array.isArray(expect.response_includes_any) && expect.response_includes_any.length > 0) {
  if (!includesAny(responseText, expect.response_includes_any)) {
    errors.push(
      `respuesta no incluye ninguno de: ${expect.response_includes_any.join(", ")}`
    );
  }
}

if (Array.isArray(expect.response_not_includes) && expect.response_not_includes.length > 0) {
  if (!notIncludesAny(responseText, expect.response_not_includes)) {
    errors.push(
      `respuesta contiene texto prohibido: ${expect.response_not_includes.join(", ")}`
    );
  }
}

const passed = errors.length === 0;

return [
  {
    json: {
      run_id: input.run_id,
      scenario_id: input.scenario_id,
      scenario_name: input.scenario_name,
      step_index: input.step_index,
      text_sent: input.text,
      passed,
      errors,

      lead_id: lead.id || null,
      bot_response: responseText,

      state_snapshot: {
        previous: {
          stage: previousState.stage || null,
          next_goal: previousState.next_goal || null,
          last_bot_action: previousState.last_bot_action || null,
          service_interest: previousState.service_interest || null,
          vehicle_type: previousState.vehicle_type || null,
          district: previousState.district || null
        },
        current: {
          stage,
          next_goal: nextGoal,
          last_bot_action: lastBotAction,
          service_interest: currentState.service_interest || null,
          vehicle_type: currentState.vehicle_type || null,
          district: currentState.district || null
        },
        changed: stateChanged
      },

      audit_snapshot: {
        flow_name: lastAudit.flow_name || null,
        decision: lastAudit.decision || null,
        idempotency_key: lastAudit.idempotency_key || null,
        meta: lastAudit.meta || null,
        created_at: lastAudit.created_at || null
      },

      qa_checks: {
        has_bot_response: hasBotResponse,
        has_action: hasAction,
        state_changed: stateChanged,
        has_audit: hasAudit
      },

      created_at: new Date().toISOString()
    }
  }
];

